import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { Clock, Calendar, User, Download, Filter, TrendingUp, Award } from 'lucide-react';

const ControlePonto = () => {
  const [registros, setRegistros] = useState([]);
  const [funcionarios, setFuncionarios] = useState([]);
  const [filtroFuncionario, setFiltroFuncionario] = useState('todos');
  const [filtroPeriodo, setFiltroPeriodo] = useState('mes');
  const [loading, setLoading] = useState(true);
  const [stats, setStats] = useState({});

  useEffect(() => {
    loadData();
  }, [filtroFuncionario, filtroPeriodo]);

  const loadData = async () => {
    setLoading(true);
    try {
      const [regRes, funcRes] = await Promise.all([
        axios.get('/api/admin/ponto/registros', {
          params: { funcionario_id: filtroFuncionario !== 'todos' ? filtroFuncionario : null, periodo: filtroPeriodo }
        }),
        axios.get('/api/admin/funcionarios')
      ]);
      setRegistros(regRes.data || []);
      setFuncionarios(funcRes.data || []);
      calcularStats(regRes.data || []);
    } catch (err) {
      console.error('Erro ao carregar dados:', err);
    } finally {
      setLoading(false);
    }
  };

  const calcularStats = (regs) => {
    const statsPorFunc = {};
    regs.forEach(reg => {
      if (!statsPorFunc[reg.funcionario_id]) {
        statsPorFunc[reg.funcionario_id] = {
          nome: reg.funcionario_nome,
          totalHoras: 0,
          totalDias: 0,
          mediaHorasDia: 0
        };
      }
      if (reg.duracao_minutos) {
        statsPorFunc[reg.funcionario_id].totalHoras += reg.duracao_minutos / 60;
        statsPorFunc[reg.funcionario_id].totalDias += 1;
      }
    });

    Object.keys(statsPorFunc).forEach(id => {
      const s = statsPorFunc[id];
      s.mediaHorasDia = s.totalDias > 0 ? s.totalHoras / s.totalDias : 0;
    });

    setStats(statsPorFunc);
  };

  const formatarDuracao = (minutos) => {
    if (!minutos) return '--';
    const horas = Math.floor(minutos / 60);
    const mins = Math.floor(minutos % 60);
    return `${horas}h ${mins}m`;
  };

  const formatarDataHora = (dataStr) => {
    if (!dataStr) return '--';
    const data = new Date(dataStr);
    return data.toLocaleString('pt-BR', { 
      day: '2-digit', 
      month: '2-digit', 
      year: 'numeric',
      hour: '2-digit', 
      minute: '2-digit' 
    });
  };

  const exportarRelatorio = () => {
    const csv = [
      ['Funcionário', 'Login', 'Logout', 'Duração', 'Status'],
      ...registros.map(r => [
        r.funcionario_nome,
        formatarDataHora(r.login_em),
        r.logout_em ? formatarDataHora(r.logout_em) : 'Em andamento',
        formatarDuracao(r.duracao_minutos),
        r.logout_em ? 'Completo' : 'Ativo'
      ])
    ].map(row => row.join(',')).join('\n');

    const blob = new Blob([csv], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `ponto_${new Date().toISOString().split('T')[0]}.csv`;
    link.click();
    URL.revokeObjectURL(url);
  };

  const funcionarioSelecionado = filtroFuncionario !== 'todos' ? stats[filtroFuncionario] : null;

  if (loading) {
    return (
      <div className="flex justify-center items-center h-64">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600"></div>
      </div>
    );
  }

  return (
    <div className="p-6 space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-gray-900 flex items-center gap-2">
            <Clock className="h-7 w-7 text-blue-600" />
            Controle de Ponto
          </h1>
          <p className="text-sm text-gray-500 mt-1">
            Registro de horários de entrada e saída dos funcionários
          </p>
        </div>
        <button
          onClick={exportarRelatorio}
          className="flex items-center gap-2 bg-green-500 text-white px-4 py-2 rounded-lg hover:bg-green-600 transition-colors"
        >
          <Download className="h-4 w-4" />
          Exportar CSV
        </button>
      </div>

      {/* Filtros */}
      <div className="bg-white rounded-lg shadow p-4 flex gap-4 flex-wrap">
        <div className="flex items-center gap-2">
          <Filter className="h-5 w-5 text-gray-400" />
          <select
            value={filtroFuncionario}
            onChange={(e) => setFiltroFuncionario(e.target.value)}
            className="px-3 py-2 border border-gray-300 rounded-lg text-sm focus:ring-2 focus:ring-blue-500"
          >
            <option value="todos">Todos os funcionários</option>
            {funcionarios.filter(f => f.ativo).map(f => (
              <option key={f.id} value={f.id}>{f.nome}</option>
            ))}
          </select>
        </div>
        <div className="flex items-center gap-2">
          <Calendar className="h-5 w-5 text-gray-400" />
          <select
            value={filtroPeriodo}
            onChange={(e) => setFiltroPeriodo(e.target.value)}
            className="px-3 py-2 border border-gray-300 rounded-lg text-sm focus:ring-2 focus:ring-blue-500"
          >
            <option value="hoje">Hoje</option>
            <option value="semana">Esta semana</option>
            <option value="mes">Este mês</option>
            <option value="todos">Todos os registros</option>
          </select>
        </div>
      </div>

      {/* Stats Cards */}
      {funcionarioSelecionado && (
        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
          <div className="bg-gradient-to-br from-blue-500 to-blue-600 rounded-lg shadow p-6 text-white">
            <div className="flex items-center justify-between mb-2">
              <Clock className="h-8 w-8 opacity-80" />
              <TrendingUp className="h-5 w-5" />
            </div>
            <p className="text-sm opacity-90">Total de Horas</p>
            <p className="text-3xl font-bold mt-1">{funcionarioSelecionado.totalHoras.toFixed(1)}h</p>
          </div>
          <div className="bg-gradient-to-br from-green-500 to-green-600 rounded-lg shadow p-6 text-white">
            <div className="flex items-center justify-between mb-2">
              <Calendar className="h-8 w-8 opacity-80" />
            </div>
            <p className="text-sm opacity-90">Dias Trabalhados</p>
            <p className="text-3xl font-bold mt-1">{funcionarioSelecionado.totalDias}</p>
          </div>
          <div className="bg-gradient-to-br from-purple-500 to-purple-600 rounded-lg shadow p-6 text-white">
            <div className="flex items-center justify-between mb-2">
              <Award className="h-8 w-8 opacity-80" />
            </div>
            <p className="text-sm opacity-90">Média Horas/Dia</p>
            <p className="text-3xl font-bold mt-1">{funcionarioSelecionado.mediaHorasDia.toFixed(1)}h</p>
          </div>
        </div>
      )}

      {/* Resumo Geral */}
      {filtroFuncionario === 'todos' && Object.keys(stats).length > 0 && (
        <div className="bg-white rounded-lg shadow overflow-hidden">
          <div className="p-4 border-b border-gray-200">
            <h3 className="font-semibold text-gray-900">Resumo por Funcionário</h3>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full">
              <thead className="bg-gray-50">
                <tr>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase">Funcionário</th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase">Total Horas</th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase">Dias</th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase">Média/Dia</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-gray-200">
                {Object.values(stats).map((s, idx) => (
                  <tr key={idx} className="hover:bg-gray-50">
                    <td className="px-6 py-4 whitespace-nowrap">
                      <div className="flex items-center gap-3">
                        <div className="w-8 h-8 bg-gradient-to-br from-blue-500 to-purple-500 rounded-full flex items-center justify-center">
                          <span className="text-white text-sm font-bold">{s.nome.charAt(0)}</span>
                        </div>
                        <span className="font-medium text-gray-900">{s.nome}</span>
                      </div>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900 font-semibold">
                      {s.totalHoras.toFixed(1)}h
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-600">
                      {s.totalDias}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-600">
                      {s.mediaHorasDia.toFixed(1)}h
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}

      {/* Tabela de Registros */}
      <div className="bg-white rounded-lg shadow overflow-hidden">
        <div className="p-4 border-b border-gray-200">
          <h3 className="font-semibold text-gray-900">Registros Detalhados</h3>
        </div>
        <div className="overflow-x-auto">
          <table className="w-full">
            <thead className="bg-gray-50">
              <tr>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase">Funcionário</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase">Login</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase">Logout</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase">Duração</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase">Status</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-200">
              {registros.length === 0 ? (
                <tr>
                  <td colSpan="5" className="px-6 py-12 text-center text-gray-400">
                    <Clock className="h-12 w-12 mx-auto mb-2 opacity-50" />
                    <p>Nenhum registro encontrado</p>
                  </td>
                </tr>
              ) : (
                registros.map((reg) => (
                  <tr key={reg.id} className="hover:bg-gray-50">
                    <td className="px-6 py-4 whitespace-nowrap">
                      <div className="flex items-center gap-3">
                        <div className="w-8 h-8 bg-gradient-to-br from-indigo-500 to-blue-500 rounded-full flex items-center justify-center">
                          <span className="text-white text-sm font-bold">
                            {reg.funcionario_nome?.charAt(0) || 'F'}
                          </span>
                        </div>
                        <span className="font-medium text-gray-900">{reg.funcionario_nome}</span>
                      </div>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-600">
                      {formatarDataHora(reg.login_em)}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-600">
                      {reg.logout_em ? formatarDataHora(reg.logout_em) : (
                        <span className="text-green-600 font-medium flex items-center gap-1">
                          <span className="w-2 h-2 bg-green-500 rounded-full animate-pulse"></span>
                          Em andamento
                        </span>
                      )}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm font-semibold text-gray-900">
                      {formatarDuracao(reg.duracao_minutos)}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap">
                      {reg.logout_em ? (
                        <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-gray-100 text-gray-800">
                          Completo
                        </span>
                      ) : (
                        <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-green-100 text-green-800">
                          Ativo
                        </span>
                      )}
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default ControlePonto;
